// APT41 / Winnti — signed-loader + side-loaded DLL co-located outside Program Files
let RecentWindow = 7d;
// Loaders APT41 / Winnti repeatedly abuse (FireEye / Mandiant / TrendMicro reporting)
let KnownLoaders = dynamic([
    "googleupdate.exe","chrome_frame_helper.exe","hkcmd.exe","oleview.exe",
    "potplayermini.exe","vlc.exe","hpqhvind.exe","nvsmartmaxapp.exe",
    "acrotray.exe","bdreinit.exe","esetonlinescanner.exe","avp.exe"
]);
// Sibling DLL names APT41 has dropped to hijack the loaders above
let HijackDlls = dynamic([
    "libcurl.dll","log.dll","goopdate.dll","hpqhvsei.dll","nvsmartmax.dll",
    "libvlc.dll","version.dll","vftrace.dll","dsparse.dll","wtsapi32.dll",
    "potplayer.dll","libcef.dll","sensapi.dll","secur32.dll"
]);
let LoaderRuns =
    DeviceImageLoadEvents
    | where Timestamp > ago(RecentWindow)
    | where tolower(InitiatingProcessFileName) in (KnownLoaders)
    | where tolower(FileName) in (HijackDlls)
    // The hijacked DLL lives in the SAME directory as the signed loader,
    // not in System32 / WinSxS — that is the side-loading invariant.
    | where tolower(FolderPath) =~ tolower(InitiatingProcessFolderPath)
    // Exclude legitimate install locations
    | where InitiatingProcessFolderPath !startswith @"C:\Program Files"
    | where InitiatingProcessFolderPath !startswith @"C:\Program Files (x86)"
    | where InitiatingProcessFolderPath !startswith @"C:\Windows\"
    | project Timestamp, DeviceId, DeviceName,
              LoaderName  = InitiatingProcessFileName,
              LoaderPath  = InitiatingProcessFolderPath,
              LoaderSHA256 = InitiatingProcessSHA256,
              SideLoadedDll = FileName,
              DllSHA256     = SHA256,
              AccountName   = InitiatingProcessAccountName;
// Confirm the side-loaded DLL was recently dropped (not pre-existing legit file)
let RecentDrops =
    DeviceFileEvents
    | where Timestamp > ago(RecentWindow)
    | where ActionType in ("FileCreated","FileRenamed","FileModified")
    | where tolower(FileName) in (HijackDlls)
    | project DropTime = Timestamp, DeviceId, DroppedDll = FileName,
              DropPath = FolderPath, DropperProc = InitiatingProcessFileName,
              DropperCmd = InitiatingProcessCommandLine, DropSHA256 = SHA256;
LoaderRuns
| join kind=inner RecentDrops on DeviceId, $left.SideLoadedDll == $right.DroppedDll
| where DropTime <= Timestamp and DropTime > Timestamp - 30d
| project Timestamp, DeviceName, AccountName,
          LoaderName, LoaderPath, LoaderSHA256,
          SideLoadedDll, DllSHA256,
          DropTime, DropPath, DropperProc, DropperCmd
| order by Timestamp desc
